// =============================================
// CONFIGURATION - LinkedIn Lead Search
// =============================================
// This flow uses Google Custom Search API (FREE - 100 queries/day)
// NO credit card needed, NO paid APIs
//
// SETUP STEPS (one-time, 5 minutes):
// 1. Go to: https://programmablesearchengine.google.com/
// 2. Click 'Add' to create a new search engine
// 3. Name it: 'LinkedIn Profile Search'
// 4. Under 'Sites to search', add: linkedin.com
// 5. Click Create → copy the 'Search engine ID' (cx)
// 6. Go to: https://console.cloud.google.com/apis/credentials
// 7. Create a project (or use existing one)
// 8. Enable 'Custom Search API' under APIs & Services → Library
// 9. Go to Credentials → Create Credentials → API Key
// 10. Copy the API Key and paste below
// =============================================

const input = $input.first().json;
const body = input.body || input;

return [{
  json: {
    chatInput: body.query || 'Find 10 IT decision makers',
    requestedCount: parseInt(body.lead_count) || 10,
    // PASTE YOUR VALUES HERE:
    googleCseKey: 'YOUR_GOOGLE_CSE_API_KEY',
    googleCseCx: 'YOUR_GOOGLE_CSE_ENGINE_ID'
  }
}];

// Build Google search query for LinkedIn profiles
const input = items[0].json.output || items[0].json;
const config = $('📋 Config + Input').first().json;

const roles = input.roles || [];
const leadCount = Math.min(input.lead_count || 10, 10); // Google CSE max 10/call
const filters = input.filters || [];
const location = input.location || '';
const keywords = input.keywords || [];

// Helper: create "term1" OR "term2" format
function quoted(terms) {
  return terms.filter(t => t && t.trim())
    .map(t => '"' + t.trim() + '"')
    .join(' OR ');
}

// Helper: build location part of query
function locQuery(loc) {
  if (!loc) return '';
  const parts = loc.split(/\s+(?:OR|or)\s+|,\s*/)
    .map(l => l.trim()).filter(Boolean);
  if (parts.length === 1) return '"' + parts[0] + '"';
  if (parts.length > 1) return '(' + parts.map(l => '"' + l + '"').join(' OR ') + ')';
  return '';
}

// Build the search query
let q = 'site:linkedin.com/in';
const parts = [];
if (roles.length) parts.push(quoted(roles));
if (location) parts.push(locQuery(location));
if (filters.length) parts.push(quoted(filters.slice(0, 3)));
if (keywords.length && !roles.length) parts.push(quoted(keywords.slice(0, 3)));
if (parts.length) q += ' ' + parts.join(' ');

return [{
  json: {
    searchQuery: q.trim(),
    leadCount: leadCount,
    googleCseKey: config.googleCseKey,
    googleCseCx: config.googleCseCx,
    parsedInput: input
  }
}];

// Extract leads from Google Custom Search results
const input = $input.first().json;
const searchInfo = $('🔍 Search Builder').first().json;

// Handle API errors
if (input.error) {
  const msg = input.error.message || input.error.errors?.[0]?.message || 'Google CSE error';
  return [{json: {
    hasResults: false,
    leads: [],
    sql: '',
    leadsFound: 0,
    searchQuery: searchInfo.searchQuery,
    error: msg
  }}];
}

const emailRegex = /[a-zA-Z0-9._%+-]+@[a-zA-Z0-9.-]+\.[a-z]{2,}/gi;
const leads = [];
const items_list = input.items || [];

for (const result of items_list) {
  const link = result.link || '';
  // Only keep actual profile URLs
  if (!link.includes('linkedin.com/in/')) continue;

  const rawTitle = result.title || '';
  const snippet = result.snippet || '';

  // Clean title: remove '| LinkedIn', '- LinkedIn' suffix
  const cleanTitle = rawTitle.replace(/\s*[-–|]\s*LinkedIn\s*$/i, '').trim();

  // Split: "Name - Role - Company" or "Name - Role"
  const titleParts = cleanTitle.split(/\s*[-–]\s*/);
  const name = (titleParts[0] || '').trim();
  const role = (titleParts[1] || '').trim();
  let company = (titleParts[2] || '').trim();

  // Try to get company from pagemap metatags (og:title)
  if (!company) {
    const ogTitle = result.pagemap?.metatags?.[0]?.['og:title'] || '';
    const ogParts = ogTitle.replace(/\s*[-–|]\s*LinkedIn\s*$/i, '').split(/\s*[-–]\s*/);
    if (ogParts.length >= 3) company = ogParts[ogParts.length - 1].trim();
  }

  // Try to extract email from snippet
  const emails = snippet.match(emailRegex);
  const email = (emails && emails.length > 0) ? emails[0].trim() : '';

  // Skip if we already have this URL
  if (leads.some(l => l.linkedinUrl === link)) continue;

  leads.push({
    name: name,
    role: role,
    company: company,
    linkedinUrl: link,
    email: email,
    snippet: snippet.substring(0, 300),
    scrapedAt: new Date().toISOString()
  });
}

// Build SQL bulk upsert if we have results
let sql = '';
if (leads.length > 0) {
  const esc = (s) => (s || '').replace(/'/g, "''").substring(0, 500);
  const rows = leads.map(l => {
    const nameParts = (l.name || '').trim().split(/\s+/);
    const firstName = esc(nameParts[0] || '');
    const lastName = esc(nameParts.slice(1).join(' ') || '');
    return "('" + esc(l.linkedinUrl) + "', '" + esc(l.name) + "', '" + firstName + "', '" + lastName + "', '" + esc(l.role) + "', '" + esc(l.company) + "', ARRAY['linkedin-search']::text[], '" + esc(l.snippet) + "', NOW(), 40, false)";
  }).join(',\n');

  sql = 'INSERT INTO scraped_profiles (linkedin_url, full_name, first_name, last_name, headline, company, tags, notes, first_seen_at, lead_score, is_potential_lead) VALUES ' + rows + ' ON CONFLICT (linkedin_url) DO UPDATE SET headline = COALESCE(NULLIF(EXCLUDED.headline, \'\'), scraped_profiles.headline), company = COALESCE(NULLIF(EXCLUDED.company, \'\'), scraped_profiles.company), tags = (SELECT ARRAY(SELECT DISTINCT unnest(COALESCE(scraped_profiles.tags, ARRAY[]::text[]) || EXCLUDED.tags))), notes = COALESCE(NULLIF(EXCLUDED.notes, \'\'), scraped_profiles.notes) RETURNING id, linkedin_url, full_name, headline, company;';
}

return [{json: {
  hasResults: leads.length > 0,
  leads: leads,
  sql: sql,
  leadsFound: leads.length,
  searchQuery: searchInfo.searchQuery,
  parsedInput: searchInfo.parsedInput
}}];

// Format success response
const data = $('📊 Extract Leads').first().json;
const dbResult = $input.first().json;

return [{json: {
  success: true,
  leads_found: data.leadsFound,
  leads: data.leads,
  search_query: data.searchQuery,
  parsed_input: data.parsedInput,
  saved_to_db: true,
  message: 'Found ' + data.leadsFound + ' LinkedIn profiles. Saved to database.'
}}];

// No results or error response
const data = $('📊 Extract Leads').first().json;

return [{json: {
  success: true,
  leads_found: 0,
  leads: [],
  search_query: data.searchQuery || '',
  parsed_input: data.parsedInput || {},
  error: data.error || null,
  message: data.error
    ? 'Search error: ' + data.error + '. Check Google CSE configuration in the n8n flow.'
    : 'No LinkedIn profiles found. Try different or broader search terms.'
}}];
